`, "",{"version":3,"sources":["webpack://./src/STH_ExportAll/界面.vue"],"names":[],"mappings":"AA8JA,wCACE,cAAe,CACf,YAAa,CACb,eAAgB,CAChB,oBAAqB,CACrB,cACF","sourcesContent":["<template>\n  <div class=\"sth-export-all\">\n    <div class=\"inline-drawer\">\n      <div class=\"inline-drawer-toggle inline-drawer-header\">\n        <b>{{ `STH 一键导出` }}</b>\n        <div class=\"inline-drawer-icon fa-solid fa-circle-chevron-down down\"></div>\n      </div>\n      <div class=\"inline-drawer-content\">\n        <div class=\"sth-export-all_block flex-container\">\n          <input\n            class=\"menu_button\"\n            type=\"submit\"\n            :value=\"isExporting ? '导出中...' : '导出全部'\"\n            :disabled=\"isExporting\"\n            @click=\"handleExport\"\n          />\n        </div>\n\n        <div v-if=\"exportStatus\" class=\"sth-export-all_status\">\n          {{ exportStatus }}\n        </div>\n\n        <hr class=\"sysHR\" />\n      </div>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { useSettingsStore } from './settings';\n\n// Keep reference to settings store\nuseSettingsStore();\n\nconst isExporting = ref(false);\nconst exportStatus = ref('');\n\nconst handleExport = async () => {\n  if (isExporting.value) return;\n\n  isExporting.value = true;\n  exportStatus.value = '正在加载压缩库...';\n\n  try {\n    const JSZip = await loadJSZip();\n\n    exportStatus.value = '正在获取角色列表...';\n    const character_names = getCharacterNames();\n\n    if (!Array.isArray(character_names) || character_names.length === 0) {\n      throw new Error('没有找到角色');\n    }\n\n    const exportData: { name: string; chats: object }[] = [];\n\n    for (let i = 0; i < character_names.length; i++) {\n      const name = character_names[i];\n      exportStatus.value = `正在导出角色 ${i + 1}/${character_names.length}: ${name}`;\n\n      try {\n        const chats_brief_raw = await getChatHistoryBrief(name);\n\n        // Ensure chats_brief is an array\n        let chatsArray: any[] = [];\n        if (Array.isArray(chats_brief_raw)) {\n          chatsArray = chats_brief_raw;\n        } else if (chats_brief_raw && typeof chats_brief_raw === 'object') {\n          // It might be a Map or object with numeric keys\n          chatsArray = Object.values(chats_brief_raw as object);\n        }\n\n        if (chatsArray.length > 0) {\n          const chats_detail = await getChatHistoryDetail(chatsArray, false);\n          exportData.push({\n            name: String(name),\n            chats: (chats_detail && typeof chats_detail === 'object') ? chats_detail : {}\n          });\n        } else {\n          exportData.push({ name: String(name), chats: {} });\n        }\n      } catch (err) {\n        console.warn(`Failed to export ${name}:`, err);\n        exportData.push({ name: String(name), chats: {} });\n      }\n    }\n\n    exportStatus.value = '正在压缩数据...';\n\n    const zip = new JSZip();\n    for (const charData of exportData) {\n      try {\n        const safeName = String(charData.name || 'unknown').replace(/[\\\\/:*?\"<>|]/g, '_');\n        const chatsData = charData.chats && typeof charData.chats === 'object' ? charData.chats : {};\n        zip.file(`${safeName}/chats.json`, JSON.stringify(chatsData, null, 2));\n        zip.file(`${safeName}/meta.json`, JSON.stringify({\n          name: safeName,\n          exportDate: new Date().toISOString(),\n        }));\n      } catch (err) {\n        console.warn(`Failed to add ${charData.name} to zip:`, err);\n      }\n    }\n\n    const zipBlob = await zip.generateAsync({\n      type: 'blob',\n      compression: 'DEFLATE',\n      compressionOptions: { level: 6 },\n    });\n\n    exportStatus.value = '正在下载...';\n\n    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');\n    const filename = `STH_Export_${timestamp}.zip`;\n\n    downloadBlob(zipBlob, filename);\n\n    exportStatus.value = `导出完成！共导出 ${character_names.length} 个角色`;\n    toastr.success('导出成功！');\n\n    _.delay(() => {\n      exportStatus.value = '';\n    }, 3000);\n  } catch (error) {\n    console.error('Export failed:', error);\n    exportStatus.value = '导出失败: ' + (error as Error).message;\n    toastr.error('导出失败: ' + (error as Error).message);\n  } finally {\n    isExporting.value = false;\n  }\n};\n\nfunction loadJSZip(): Promise<any> {\n  return new Promise((resolve, reject) => {\n    if ((window as any).JSZip) {\n      resolve((window as any).JSZip);\n      return;\n    }\n    const script = document.createElement('script');\n    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';\n    script.onload = () => resolve((window as any).JSZip);\n    script.onerror = () => reject(new Error('JSZip 加载失败'));\n    document.head.appendChild(script);\n  });\n}\n\nfunction downloadBlob(blob: Blob, filename: string): void {\n  const url = URL.createObjectURL(blob);\n  const a = document.createElement('a');\n  a.href = url;\n  a.download = filename;\n  document.body.appendChild(a);\n  a.click();\n  document.body.removeChild(a);\n  URL.revokeObjectURL(url);\n}\n</script>\n\n<style scoped>\n.sth-export-all-status {\n  font-size: 12px;\n  opacity: 0.75;\n  line-height: 1.5;\n  word-break: break-all;\n  margin-top: 8px;\n}\n</style>\n"],"sourceRoot":""}]);
